  const existing = await getOrder(client, orderId);
  if (!existing) return null;
  const updated = { ...existing, status };
  await client.query('UPDATE orders SET doc = $1 WHERE order_id = $2', [JSON.stringify(updated), orderId]);
  return updated;
}
